#include<bits/stdc++.h>
#define ll long long
using namespace std;
const int MAXN=3e5+1;
ll n,ans=0,a[MAXN],r[MAXN];
void Merge_Sort(int s,int t){
	if(s==t)return;long long mid=(s+t)/2;
	Merge_Sort(s,mid);Merge_Sort(mid+1,t);
	long long i=s,j=mid+1,k=s;while(i<=mid&&j<=t){
		if(a[i]>=a[j])r[k]=a[i],++k,++i;
		else r[k]=a[j],++k,++j,ans+=mid-i+1;
	}while(i<=mid)r[k]=a[i],++k,++i;
	while(j<=t)r[k]=a[j],++k,++j;
	for(int i=s;i<=t;++i)a[i]=r[i];
}int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	scanf("%lld",&n);
	for(int i=1;i<=n;++i)scanf("%lld",a+i);
	Merge_Sort(1,n);printf("%lld",ans);
	return false;
}
